const orderCard = { background: '#fff', borderRadius: '28px', boxShadow: '0 10px 15px -3px rgba(0,0,0,0.05)', border: '1px solid #f1f5f9', position: 'relative', overflow: 'hidden', transition: 'all 0.3s ease' };
const orderHeader = { padding: '18px 24px', display: 'flex', justifyContent: 'space-between', background: '#f8fafc' };
const dateText = { color: '#94a3b8', fontSize: '0.85rem', fontWeight: '600' };
const statusText = { fontSize: '0.85rem', fontWeight: '800' };

const stepperWrapper = { padding: '40px 40px 20px 40px', position: 'relative' };
