const stepperFill = { height: '100%', background: '#3182ce', borderRadius: '10px', transition: 'width 0.4s ease' };
const nodesContainer = { position: 'absolute', top: '30px', left: '40px', right: '40px', display: 'flex', justifyContent: 'space-between' };
const nodeGroup = { display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '8px' };
const node = { width: '28px', height: '28px', borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 2 };
const nodeLabel = { fontSize: '0.65rem', fontWeight: '700', color: '#64748b', textTransform: 'uppercase' };
const truckFloat = { position: 'absolute', top: '15px', background: 'white', borderRadius: '50%', padding: '4px', boxShadow: '0 4px 10px rgba(0,0,0,0.1)' };

const bodyCard = { padding: '24px' };
const localRow = { display: 'flex', alignItems: 'center', gap: '15px', marginBottom: '20px' };
