const cancelButton = { 
  width: '100%', 
  padding: '12px', 
  borderRadius: '12px', 
  border: '1px solid #fee2e2', 
  background: '#fef2f2', 
  color: '#ef4444', 
  fontWeight: '700', 
  fontSize: '0.85rem', 
  cursor: 'pointer', 
  display: 'flex', 
  alignItems: 'center', 
  justifyContent: 'center', 
  gap: '8px',
  transition: 'background 0.2s'
};

const msgContainer = { display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', height: '100vh', gap: '10px' };

export default MisPedidosCliente;
